"use client";

import { useState, useCallback } from "react";
import Navbar from "@/components/ui/Navbar";
import ParallaxBackground from "@/components/ui/ParallaxBackground";
import CursorFollower from "@/components/ui/CursorFollower";
import HeroScene from "@/components/scenes/HeroScene";
import ChaosScene from "@/components/scenes/ChaosScene";
import CuratedScene from "@/components/scenes/CuratedScene";
import SpinRitual from "@/components/scenes/SpinRitual";
import ResultScene from "@/components/scenes/ResultScene";
import GridScene from "@/components/scenes/GridScene";
import FooterScene from "@/components/scenes/FooterScene";
import { DEMO_MOVIES } from "@/lib/constants";
import { Movie } from "@/types/movie";

export default function Home() {
  const [chosenMovie, setChosenMovie] = useState<Movie | null>(null);
  const movies = DEMO_MOVIES;

  const handleSpinResult = useCallback((movie: Movie) => {
    setChosenMovie(movie);
    setTimeout(() => {
      const el = document.getElementById("result");
      if (el) el.scrollIntoView({ behavior: "smooth" });
    }, 2500);
  }, []);

  const handleMoodSelect = useCallback((moodId: string, genreIds: number[]) => {
    setTimeout(() => {
      const el = document.getElementById("spin");
      if (el) el.scrollIntoView({ behavior: "smooth" });
    }, 300);
  }, []);

  const gridMovies = chosenMovie
    ? movies.filter((m) => m.id !== chosenMovie.id).slice(0, 12)
    : movies.slice(0, 12);

  return (
    <main className="relative">
      {/* Background layers */}
      <ParallaxBackground />
      <CursorFollower />
      <Navbar />

      {/* Content ΓÇö sits above parallax bg */}
      <div className="relative z-10">
        <HeroScene movies={movies} />
        <ChaosScene movies={movies} />
        <CuratedScene movies={movies} onMoodSelect={handleMoodSelect} />
        <SpinRitual movies={movies} onResult={handleSpinResult} />
        <ResultScene movie={chosenMovie} />
        <GridScene movies={gridMovies} />
        <FooterScene />
      </div>
    </main>
  );
}

"use client";

import { useRef, useLayoutEffect, useState, useCallback } from "react";
import { motion, useInView } from "framer-motion";
import { gsap, ScrollTrigger } from "@/lib/gsapConfig";
import { Movie } from "@/types/movie";
import { getImageUrl } from "@/lib/tmdb";
import { IMAGE_SIZES, ANIMATION } from "@/lib/constants";
import { useReducedMotion } from "@/hooks/useReducedMotion";

interface ChaosSceneProps {
  movies: Movie[];
}

/*
  FOLLOW.ART-inspired poster choreography with GSAP ScrollTrigger.
  
  Philosophy:
  - Cards are cinematic floating objects inside a shared perspective container.
  - They enter diagonally as if wind is carrying them across space.
  - Scroll moves the camera through the card field via GSAP scrub, not individual cards.
  - Mouse tilts the entire perspective stage via GSAP spring.
  - Typography is anchored behind everything ΓÇö cards drift over it.
  - Easing is slow, confident, editorial. No bounce. No elastic.
*/

// Poster layout: final resting positions in the perspective field
const POSTER_CHOREOGRAPHY = [
  // Row 1 ΓÇö top-left cluster, slightly receded
  { x: -420, y: -200, z: -80,  rotX: 4,   rotY: 12,  rotZ: -8,   w: 200, h: 300, delay: 0    },
  { x: -180, y: -240, z: 20,   rotX: -3,  rotY: -8,  rotZ: 5,    w: 220, h: 330, delay: 0.12 },
  { x: 60,   y: -190, z: -40,  rotX: 2,   rotY: 6,   rotZ: -3,   w: 190, h: 285, delay: 0.06 },
  
  // Row 2 ΓÇö center band, prominent
  { x: -340, y: -20,  z: 60,   rotX: -2,  rotY: -10, rotZ: 6,    w: 210, h: 315, delay: 0.18 },
  { x: -100, y: 10,   z: 100,  rotX: 3,   rotY: 5,   rotZ: -4,   w: 240, h: 360, delay: 0.24 },
  { x: 150,  y: -40,  z: 40,   rotX: -4,  rotY: -7,  rotZ: 3,    w: 200, h: 300, delay: 0.15 },
  { x: 380,  y: -10,  z: -20,  rotX: 2,   rotY: 9,   rotZ: -5,   w: 190, h: 285, delay: 0.21 },

  // Row 3 ΓÇö bottom spread, fading depth
  { x: -400, y: 200,  z: -60,  rotX: -3,  rotY: 8,   rotZ: 4,    w: 180, h: 270, delay: 0.30 },
  { x: -160, y: 220,  z: 30,   rotX: 4,   rotY: -6,  rotZ: -3,   w: 200, h: 300, delay: 0.27 },
  { x: 100,  y: 180,  z: -30,  rotX: -2,  rotY: 5,   rotZ: 6,    w: 185, h: 278, delay: 0.33 },
  { x: 340,  y: 210,  z: 50,   rotX: 3,   rotY: -9,  rotZ: -4,   w: 210, h: 315, delay: 0.36 },

  // Peripheral accents ΓÇö edges of frame
  { x: 480,  y: -180, z: -100, rotX: 5,   rotY: 14,  rotZ: -7,   w: 170, h: 255, delay: 0.09 },
  { x: -500, y: 80,   z: -90,  rotX: -4,  rotY: -12, rotZ: 5,    w: 175, h: 263, delay: 0.39 },
  { x: 440,  y: 140,  z: -70,  rotX: 3,   rotY: 11,  rotZ: -6,   w: 165, h: 248, delay: 0.42 },
];

// Confident editorial easing ΓÇö slow in, slow out, no bounce
const WIND_EASE: [number, number, number, number] = [0.22, 0.61, 0.36, 1.0];

export default function ChaosScene({ movies }: ChaosSceneProps) {
  const sectionRef = useRef<HTMLDivElement>(null);
  const stageRef = useRef<HTMLDivElement>(null);
  const isInView = useInView(sectionRef, { once: true, margin: "-8%" });
  const [mousePos, setMousePos] = useState({ x: 0, y: 0 });
  const prefersReduced = useReducedMotion();

  // ΓöÇΓöÇ GSAP ScrollTrigger: camera scrub through card field ΓöÇΓöÇ
  useLayoutEffect(() => {
    if (prefersReduced || !sectionRef.current || !stageRef.current) return;

    const ctx = gsap.context(() => {
      // Camera Z push ΓÇö scroll moves us "into" the card field
      // Camera Y drift ΓÇö subtle vertical shift
      ScrollTrigger.create({
        trigger: sectionRef.current,
        start: "top bottom",
        end: "bottom top",
        scrub: ANIMATION.duration.scrubLag, // 1.2s catch-up lag for cinematic feel
        animation: gsap
          .timeline()
          .fromTo(
            stageRef.current,
            { z: 80, y: 40 },
            { z: -60, y: -30, ease: "none" }
          ),
      });
    }, sectionRef);

    return () => ctx.revert();
  }, [prefersReduced]);

  // ΓöÇΓöÇ Mouse tilt on entire perspective stage (GSAP spring) ΓöÇΓöÇ
  const handleMouseMove = useCallback((e: MouseEvent) => {
    if (!sectionRef.current || !stageRef.current) return;
    const rect = sectionRef.current.getBoundingClientRect();
    const x = ((e.clientX - rect.left) / rect.width - 0.5) * 2;
    const y = ((e.clientY - rect.top) / rect.height - 0.5) * 2;
    setMousePos({ x, y });

    // GSAP spring tilt on the perspective stage
    gsap.to(stageRef.current, {
      rotateX: y * -2.5,
      rotateY: x * 3,
      duration: 0.4,
      ease: "power2.out",
      overwrite: "auto",
    });
  }, []);

  // Attach mouse listener
  useLayoutEffect(() => {
    const section = sectionRef.current;
    if (!section) return;
    section.addEventListener("mousemove", handleMouseMove, { passive: true });
    return () => section.removeEventListener("mousemove", handleMouseMove);
  }, [handleMouseMove]);

  const posters = movies.slice(0, POSTER_CHOREOGRAPHY.length);

  return (
    <section
      ref={sectionRef}
      className="scene relative min-h-[140vh] flex items-center justify-center overflow-hidden"
      id="chaos"
      style={{ perspective: `${ANIMATION.depth.perspective}px` }}
    >
      {/* Background gradient */}
      <div className="absolute inset-0 bg-gradient-to-b from-cream via-cream-warm/60 to-cream" />

      {/* ===== ANCHORED TYPOGRAPHY ΓÇö behind everything ===== */}
      <div className="absolute inset-0 flex items-center justify-center pointer-events-none z-[1]">
        <div className="text-center select-none">
          <h2
            className="font-display font-extralight tracking-[-0.02em] leading-[0.9]"
            style={{
              fontSize: "clamp(5rem, 14vw, 16rem)",
              color: "rgba(26, 26, 46, 0.06)",
              WebkitTextStroke: "1px rgba(26, 26, 46, 0.04)",
            }}
          >
            VELORA
          </h2>
        </div>
      </div>

      {/* ===== PERSPECTIVE STAGE ===== */}
      {/* GSAP ScrollTrigger controls Z + Y. Mouse tilts rotateX/Y via GSAP spring. */}
      <div
        ref={stageRef}
        className="relative w-full max-w-7xl mx-auto h-[90vh] flex items-center justify-center z-[2]"
        style={{
          transformStyle: "preserve-3d",
          willChange: "transform",
        }}
      >
        {posters.map((movie, i) => {
          const config = POSTER_CHOREOGRAPHY[i];

          // Diagonal entry vector ΓÇö cards arrive from top-right to bottom-left
          const entryAngle = -35;
          const entryDistance = 1200 + i * 80;
          const rad = (entryAngle * Math.PI) / 180;
          const entryX = Math.cos(rad) * entryDistance;
          const entryY = Math.sin(rad) * entryDistance;

          return (
            <motion.div
              key={movie.id}
              className="absolute group"
              initial={{
                x: prefersReduced ? config.x : entryX,
                y: prefersReduced ? config.y : entryY,
                rotateX: prefersReduced ? config.rotX : config.rotX * 4,
                rotateY: prefersReduced ? config.rotY : config.rotY * 3,
                rotateZ: prefersReduced ? config.rotZ : config.rotZ * 2.5,
                opacity: prefersReduced ? 1 : 0,
                scale: prefersReduced ? 1 : 0.6,
              }}
              animate={
                isInView
                  ? {
                      x: config.x,
                      y: config.y,
                      rotateX: config.rotX,
                      rotateY: config.rotY,
                      rotateZ: config.rotZ,
                      opacity: 1,
                      scale: 1,
                    }
                  : {}
              }
              transition={{
                duration: 2.2 + i * 0.06,
                delay: config.delay,
                ease: WIND_EASE,
              }}
              style={{
                left: "50%",
                top: "50%",
                marginLeft: -(config.w / 2),
                marginTop: -(config.h / 2),
                transformStyle: "preserve-3d",
                transform: `translateZ(${config.z}px)`,
                zIndex: Math.round((config.z + 100) / 20),
                willChange: "transform",
              }}
            >
              {/* The poster card */}
              <div
                className="relative rounded-xl overflow-hidden cursor-pointer transition-all duration-700"
                style={{
                  width: config.w,
                  height: config.h,
                  boxShadow: `
                    0 ${8 + (config.z + 100) * 0.15}px ${
                    30 + (config.z + 100) * 0.3
                  }px rgba(0,0,0,0.08),
                    0 ${2 + (config.z + 100) * 0.04}px ${
                    8 + (config.z + 100) * 0.1
                  }px rgba(0,0,0,0.04)
                  `,
                }}
              >
                {/* Hover: slight lift + subtle glow */}
                <div className="w-full h-full transition-transform duration-700 ease-out group-hover:translate-y-[-6px] group-hover:scale-[1.015]">
                  <img
                    src={getImageUrl(
                      movie.poster_path,
                      IMAGE_SIZES.poster.medium
                    )}
                    alt={movie.title}
                    className="w-full h-full object-cover rounded-xl"
                    loading="lazy"
                    draggable={false}
                  />
                </div>

                {/* Hover glow ΓÇö soft warm edge light */}
                <div
                  className="absolute inset-0 rounded-xl opacity-0 group-hover:opacity-100 transition-opacity duration-700 pointer-events-none"
                  style={{
                    boxShadow:
                      "inset 0 0 30px rgba(232, 168, 56, 0.08), 0 0 40px rgba(232, 168, 56, 0.06)",
                  }}
                />

                {/* Hover info ΓÇö title + rating */}
                <div className="absolute bottom-0 left-0 right-0 p-3 rounded-b-xl bg-gradient-to-t from-black/50 via-black/20 to-transparent opacity-0 group-hover:opacity-100 translate-y-2 group-hover:translate-y-0 transition-all duration-700 ease-out pointer-events-none">
                  <p className="font-display text-xs text-white/90 font-medium truncate">
                    {movie.title}
                  </p>
                  <span className="text-[10px] text-golden-light">
                    Γÿà {movie.vote_average.toFixed(1)}
                  </span>
                </div>
              </div>
            </motion.div>
          );
        })}
      </div>

      {/* ===== FOREGROUND TEXT ===== */}
      <div className="absolute inset-0 flex flex-col items-center justify-end pb-[12vh] pointer-events-none z-[3]">
        <motion.h3
          initial={{ y: 50, opacity: 0 }}
          animate={isInView ? { y: 0, opacity: 1 } : {}}
          transition={{ duration: 1.6, delay: 1.2, ease: [0.25, 0.1, 0.25, 1.0] }}
          className="font-display font-extralight text-ink text-center leading-[1.1]"
          style={{ fontSize: "var(--text-headline)" }}
        >
          500,000 films exist.
        </motion.h3>
        <motion.p
          initial={{ y: 30, opacity: 0 }}
          animate={isInView ? { y: 0, opacity: 0.5 } : {}}
          transition={{ duration: 1.4, delay: 1.8, ease: [0.25, 0.1, 0.25, 1.0] }}
          className="font-body text-ink-soft text-center mt-3"
          style={{ fontSize: "var(--text-body)" }}
        >
          How do you choose just one?
        </motion.p>
      </div>
    </section>
  );
}

"use client";

import { useRef } from "react";
import { motion, useInView } from "framer-motion";
import { Movie } from "@/types/movie";
import { getImageUrl } from "@/lib/tmdb";
import { IMAGE_SIZES, MOODS } from "@/lib/constants";
import AnimatedText from "@/components/ui/AnimatedText";

interface CuratedSceneProps {
  movies: Movie[];
  onMoodSelect?: (moodId: string, genreIds: number[]) => void;
}

export default function CuratedScene({ movies, onMoodSelect }: CuratedSceneProps) {
  const sectionRef = useRef<HTMLDivElement>(null);
  const isInView = useInView(sectionRef, { once: true, margin: "-10%" });

  const moodBackdrops: Record<string, string | null> = {};
  MOODS.forEach((mood) => {
    const found = movies.find((m) =>
      m.genre_ids.some((g) => mood.genreIds.includes(g))
    );
    moodBackdrops[mood.id] = found?.backdrop_path || null;
  });

  return (
    <section
      ref={sectionRef}
      className="scene relative min-h-screen flex flex-col items-center justify-center py-20 md:py-28"
      id="curated"
    >
      {/* Background */}
      <div className="absolute inset-0 bg-gradient-to-b from-cream via-cream-warm to-cream" />

      {/* Section heading */}
      <div className="relative z-10 text-center mb-14 md:mb-20 px-6">
        <motion.span
          initial={{ opacity: 0 }}
          animate={isInView ? { opacity: 1 } : {}}
          transition={{ duration: 1, delay: 0.2 }}
          className="font-display text-xs tracking-[0.4em] uppercase text-golden-warm/70 mb-4 block"
        >
          Curated Intelligence
        </motion.span>
        <AnimatedText
          text="What story are you craving?"
          className="font-display font-extralight text-ink"
          style={{ fontSize: "var(--text-headline)" }}
          delay={0.3}
          splitBy="words"
          as="h2"
        />
      </div>

      {/* Mood grid */}
      <div className="relative z-10 w-full max-w-6xl mx-auto px-6 grid grid-cols-2 md:grid-cols-3 gap-4 md:gap-6">
        {MOODS.map((mood, i) => {
          const backdropUrl = moodBackdrops[mood.id]
            ? getImageUrl(moodBackdrops[mood.id], IMAGE_SIZES.backdrop.medium)
            : null;

          return (
            <motion.button
              key={mood.id}
              onClick={() => onMoodSelect?.(mood.id, mood.genreIds)}
              initial={{ opacity: 0, y: 50, scale: 0.9 }}
              animate={
                isInView
                  ? { opacity: 1, y: 0, scale: 1 }
                  : {}
              }
              transition={{
                duration: 1,
                delay: 0.4 + i * 0.12,
                ease: [0.16, 1, 0.3, 1],
              }}
              className="mood-card relative overflow-hidden rounded-2xl md:rounded-3xl h-44 md:h-56
                cursor-pointer group text-left border border-white/40"
              style={{
                "--mood-glow": `${mood.accentColor}30`,
                background: "rgba(255,252,248,0.6)",
                backdropFilter: "blur(16px)",
              } as React.CSSProperties}
              data-cursor-hover
            >
              {/* Backdrop image */}
              {backdropUrl && (
                <div className="absolute inset-0">
                  <img
                    src={backdropUrl}
                    alt=""
                    className="w-full h-full object-cover opacity-60 group-hover:opacity-80 group-hover:scale-110
                      transition-all duration-700 ease-out"
                    loading="lazy"
                  />
                  <div className="absolute inset-0 bg-gradient-to-t from-white/80 via-white/30 to-transparent" />
                </div>
              )}

              {/* Accent corner glow */}
              <div
                className="absolute top-0 right-0 w-32 h-32 rounded-full opacity-20 group-hover:opacity-40
                  transition-opacity duration-500 -translate-y-1/2 translate-x-1/2"
                style={{
                  background: `radial-gradient(circle, ${mood.accentColor}, transparent)`,
                }}
              />

              {/* Label */}
              <div className="relative z-10 h-full flex flex-col justify-end p-5 md:p-6">
                <h3
                  className="font-display font-semibold text-xl md:text-2xl mb-1"
                  style={{ color: mood.accentColor }}
                >
                  {mood.label}
                </h3>
                <p className="text-xs md:text-sm text-ink-soft/70">{mood.subtitle}</p>
              </div>
            </motion.button>
          );
        })}
      </div>
    </section>
  );
}

"use client";

import { useRef, useEffect, useState } from "react";
import { motion, useInView, useScroll, useTransform } from "framer-motion";
import { Movie } from "@/types/movie";
import { getImageUrl } from "@/lib/tmdb";
import { IMAGE_SIZES } from "@/lib/constants";
import GlowButton from "@/components/ui/GlowButton";

interface ResultSceneProps {
  movie: Movie | null;
}

export default function ResultScene({ movie }: ResultSceneProps) {
  const sectionRef = useRef<HTMLDivElement>(null);
  const isInView = useInView(sectionRef, { once: true, margin: "-10%" });
  const [dominantColor, setDominantColor] = useState("rgba(232, 168, 56, 0.15)");

  const { scrollYProgress } = useScroll({
    target: sectionRef,
    offset: ["start end", "end start"],
  });

  const bgY = useTransform(scrollYProgress, [0, 1], ["-10%", "10%"]);

  // Extract dominant color from poster and inject as CSS variables
  useEffect(() => {
    if (!movie?.poster_path) return;
    const img = new window.Image();
    img.crossOrigin = "anonymous";
    img.src = getImageUrl(movie.poster_path, IMAGE_SIZES.poster.small);
    img.onload = () => {
      try {
        const canvas = document.createElement("canvas");
        canvas.width = 1;
        canvas.height = 1;
        const ctx = canvas.getContext("2d");
        if (!ctx) return;
        ctx.drawImage(img, 0, 0, 1, 1);
        const [r, g, b] = ctx.getImageData(0, 0, 1, 1).data;
        setDominantColor(`rgba(${r}, ${g}, ${b}, 0.12)`);

        // Inject dynamic theme CSS variables on :root
        const root = document.documentElement;
        root.style.setProperty("--theme-accent", `rgb(${r}, ${g}, ${b})`);
        root.style.setProperty(
          "--theme-accent-weak",
          `rgba(${r}, ${g}, ${b}, 0.15)`
        );
        root.style.setProperty(
          "--glass-tint",
          `rgba(${Math.min(r + 40, 255)}, ${Math.min(g + 40, 255)}, ${Math.min(
            b + 40,
            255
          )}, 0.55)`
        );
        root.style.setProperty(
          "--rim-color",
          `rgba(${Math.min(r + 80, 255)}, ${Math.min(g + 80, 255)}, ${Math.min(
            b + 80,
            255
          )}, 0.25)`
        );
      } catch {
        // CORS fail silently
      }
    };
  }, [movie]);

  if (!movie) {
    return (
      <section
        ref={sectionRef}
        className="scene relative min-h-[80vh] flex items-center justify-center"
        id="result"
      >
        <div className="absolute inset-0 bg-gradient-to-b from-cream to-cream-warm" />
        <motion.div
          initial={{ opacity: 0 }}
          animate={isInView ? { opacity: 1 } : {}}
          transition={{ duration: 1 }}
          className="relative z-10 text-center px-6"
        >
          <p className="font-display text-ink-muted text-lg italic">
            Spin the wheel above to reveal your film...
          </p>
        </motion.div>
      </section>
    );
  }

  return (
    <section
      ref={sectionRef}
      className="scene relative min-h-screen overflow-hidden"
      id="result"
    >
      {/* Dynamic color wash background */}
      <div
        className="absolute inset-0 transition-colors duration-1000"
        style={{ background: `linear-gradient(180deg, ${dominantColor}, var(--background))` }}
      />

      {/* Backdrop image */}
      {movie.backdrop_path && (
        <motion.div
          className="absolute inset-0 opacity-20"
          style={{ y: bgY }}
        >
          <img
            src={getImageUrl(movie.backdrop_path, IMAGE_SIZES.backdrop.large)}
            alt=""
            className="w-full h-full object-cover"
            loading="lazy"
          />
          <div className="absolute inset-0 bg-gradient-to-t from-cream via-cream/60 to-cream/30" />
        </motion.div>
      )}

      {/* Content */}
      <div className="relative z-10 min-h-screen flex items-center py-24 px-6">
        <div className="max-w-6xl mx-auto w-full grid grid-cols-1 md:grid-cols-[1fr_1.3fr] gap-10 md:gap-16 items-center">
          {/* Poster */}
          <motion.div
            initial={{ opacity: 0, x: -60 }}
            animate={isInView ? { opacity: 1, x: 0 } : {}}
            transition={{ duration: 1.2, ease: [0.16, 1, 0.3, 1] }}
            className="flex flex-col items-center md:items-end"
          >
            <div className="relative">
              <div className="w-64 md:w-80 h-96 md:h-[28rem] rounded-2xl overflow-hidden shadow-2xl">
                <img
                  src={getImageUrl(movie.poster_path, IMAGE_SIZES.poster.large)}
                  alt={movie.title}
                  className="w-full h-full object-cover"
                />
              </div>
              {/* Rating badge */}
              <div className="absolute -top-3 -right-3 w-14 h-14 rounded-full bg-golden text-white
                flex items-center justify-center text-sm font-bold shadow-lg
                ring-4 ring-cream">
                {movie.vote_average.toFixed(1)}
              </div>
            </div>
          </motion.div>

          {/* Details */}
          <motion.div
            className="space-y-5"
            initial={{ opacity: 0, x: 60 }}
            animate={isInView ? { opacity: 1, x: 0 } : {}}
            transition={{ duration: 1.2, delay: 0.3, ease: [0.16, 1, 0.3, 1] }}
          >
            {movie.tagline && (
              <p className="font-body italic text-golden-warm text-base">
                &ldquo;{movie.tagline}&rdquo;
              </p>
            )}

            <h2
              className="font-display font-extralight text-ink leading-[1.05]"
              style={{ fontSize: "var(--text-headline)" }}
            >
              {movie.title}
            </h2>

            <div className="flex items-center gap-4 text-sm text-ink-soft">
              <span>{movie.release_date?.slice(0, 4)}</span>
              <span>┬╖</span>
              <span className="flex items-center gap-1">
                <span className="text-golden">Γÿà</span> {movie.vote_average.toFixed(1)}
