"use client";

import { useState } from "react";
import Image from "next/image";
import { getImageUrl } from "@/lib/tmdb";

interface BlurUpImageProps {
  path: string | null;
  alt: string;
  type?: "poster" | "backdrop";
  fill?: boolean;
  width?: number;
  height?: number;
  className?: string;
  priority?: boolean;
}

/*
  Blur-up strategy:
  1) Tiny w92 thumbnail loaded inline as CSS-blurred placeholder (< 3KB)
  2) Next.js Image loads w342/w780 via responsive srcset
  3) Opacity transition on load for smooth reveal (700ms)

  srcset mapping:
    poster:   w92 (blur) ΓåÆ w185 (thumb) ΓåÆ w342 (mobile) ΓåÆ w500 (tablet) ΓåÆ w780 (large)
    backdrop: w92 (blur) ΓåÆ w300 (mobile) ΓåÆ w780 (tablet) ΓåÆ w1280 (desktop)
*/
const SIZE_MAP = {
  poster: "w342",
  backdrop: "w780",
} as const;

export default function BlurUpImage({
  path,
  alt,
  type = "poster",
  fill = false,
  width,
  height,
  className = "",
  priority = false,
}: BlurUpImageProps) {
  const [loaded, setLoaded] = useState(false);

  if (!path) {
    return (
      <div
        className={`relative flex items-center justify-center ${className}`}
        style={{
          width: fill ? "100%" : width,
          height: fill ? "100%" : height,
          background: "linear-gradient(135deg, #f5f0e8, #ede5d8)",
        }}
      >
        <svg
          className="w-10 h-10 text-ink-muted/30"
          fill="none"
          viewBox="0 0 24 24"
          stroke="currentColor"
        >
          <path
            strokeLinecap="round"
            strokeLinejoin="round"
            strokeWidth={1}
            d="M15.75 10.5l4.72-4.72a.75.75 0 011.28.53v11.38a.75.75 0 01-1.28.53l-4.72-4.72M4.5 18.75h9a2.25 2.25 0 002.25-2.25v-9a2.25 2.25 0 00-2.25-2.25h-9A2.25 2.25 0 002.25 7.5v9a2.25 2.25 0 002.25 2.25z"
          />
        </svg>
      </div>
    );
  }

  // Tiny placeholder ΓÇö w92 TMDB thumbnail, CSS-blurred
  const placeholderSrc = getImageUrl(path, "w92");
  const mainSrc = getImageUrl(path, SIZE_MAP[type]);

  // Responsive sizes for Next.js Image srcset
  const sizes =
    type === "poster"
      ? "(max-width: 640px) 45vw, (max-width: 1024px) 30vw, 260px"
      : "(max-width: 640px) 100vw, (max-width: 1024px) 80vw, 1280px";

  return (
    <div
      className={`relative overflow-hidden ${className}`}
      style={{
        width: fill ? "100%" : width,
        height: fill ? "100%" : height,
      }}
    >
      {/* Blur placeholder ΓÇö visible until hi-res loads */}
      {!loaded && (
        <img
          src={placeholderSrc}
          alt=""
          aria-hidden="true"
          className="absolute inset-0 w-full h-full object-cover"
          style={{ filter: "blur(20px)", transform: "scale(1.1)" }}
        />
      )}

      {fill ? (
        <Image
          src={mainSrc}
          alt={alt}
          fill
          sizes={sizes}
          className={`object-cover transition-opacity duration-700 ${
            loaded ? "opacity-100" : "opacity-0"
          }`}
          onLoad={() => setLoaded(true)}
          priority={priority}
        />
      ) : (
        <Image
          src={mainSrc}
          alt={alt}
          width={width || 300}
          height={height || 450}
          sizes={sizes}
          className={`object-cover transition-opacity duration-700 ${
            loaded ? "opacity-100" : "opacity-0"
          }`}
          onLoad={() => setLoaded(true)}
          priority={priority}
        />
      )}
    </div>
  );
}

"use client";

import { useState, useRef, useEffect } from "react";
import Image from "next/image";
import { getImageUrl } from "@/lib/tmdb";
import { IMAGE_SIZES } from "@/lib/constants";

interface CinematicImageProps {
  path: string | null;
  alt: string;
  type?: "poster" | "backdrop";
  fill?: boolean;
  width?: number;
  height?: number;
  className?: string;
  priority?: boolean;
}

export default function CinematicImage({
  path,
  alt,
  type = "poster",
  fill = false,
  width,
  height,
  className = "",
  priority = false,
}: CinematicImageProps) {
  const [loaded, setLoaded] = useState(false);
  const [error, setError] = useState(false);
  const imgRef = useRef<HTMLDivElement>(null);

  const size =
    type === "poster"
      ? IMAGE_SIZES.poster.medium
      : IMAGE_SIZES.backdrop.medium;

  const src = path ? getImageUrl(path, size) : null;

  if (!src || error) {
    return (
      <div
        className={`relative flex items-center justify-center ${className}`}
        style={{
          width: fill ? "100%" : width,
          height: fill ? "100%" : height,
          background: "linear-gradient(135deg, #f5f0e8, #ede5d8)",
        }}
      >
        <svg
          className="w-10 h-10 text-ink-muted/30"
          fill="none"
          viewBox="0 0 24 24"
          stroke="currentColor"
        >
          <path
            strokeLinecap="round"
            strokeLinejoin="round"
            strokeWidth={1}
            d="M15.75 10.5l4.72-4.72a.75.75 0 011.28.53v11.38a.75.75 0 01-1.28.53l-4.72-4.72M4.5 18.75h9a2.25 2.25 0 002.25-2.25v-9a2.25 2.25 0 00-2.25-2.25h-9A2.25 2.25 0 002.25 7.5v9a2.25 2.25 0 002.25 2.25z"
          />
        </svg>
      </div>
    );
  }

  return (
    <div
      ref={imgRef}
      className={`relative overflow-hidden ${className}`}
      style={{
        width: fill ? "100%" : width,
        height: fill ? "100%" : height,
      }}
    >
      {/* Shimmer placeholder */}
      {!loaded && (
        <div
          className="absolute inset-0 shimmer"
          style={{
            background: "linear-gradient(135deg, #f5f0e8, #ede5d8)",
          }}
        />
      )}

      {fill ? (
        <Image
          src={src}
          alt={alt}
          fill
          sizes="(max-width: 768px) 100vw, 50vw"
          className={`object-cover transition-opacity duration-700 ${
            loaded ? "opacity-100" : "opacity-0"
          }`}
          onLoad={() => setLoaded(true)}
          onError={() => setError(true)}
          priority={priority}
        />
      ) : (
        <Image
          src={src}
          alt={alt}
          width={width || 300}
          height={height || 450}
          className={`object-cover transition-opacity duration-700 ${
            loaded ? "opacity-100" : "opacity-0"
          }`}
          onLoad={() => setLoaded(true)}
          onError={() => setError(true)}
          priority={priority}
        />
      )}
    </div>
  );
}

"use client";

import { useEffect, useRef } from "react";
import { motion, useMotionValue, useSpring } from "framer-motion";

export default function CursorFollower() {
  const cursorX = useMotionValue(-100);
  const cursorY = useMotionValue(-100);
  const isHovering = useMotionValue(0);

  const springConfig = { damping: 25, stiffness: 200, mass: 0.5 };
  const x = useSpring(cursorX, springConfig);
  const y = useSpring(cursorY, springConfig);
  const scale = useSpring(1, { damping: 20, stiffness: 300 });

  useEffect(() => {
    const handleMouseMove = (e: MouseEvent) => {
      cursorX.set(e.clientX - 5);
      cursorY.set(e.clientY - 5);
    };

    const handleMouseOver = (e: MouseEvent) => {
      const target = e.target as HTMLElement;
      if (
        target.closest("button") ||
        target.closest("a") ||
        target.closest("[data-cursor-hover]") ||
        target.closest(".floating-card") ||
        target.closest(".mood-card")
      ) {
        scale.set(4.5);
      }
    };

    const handleMouseOut = () => {
      scale.set(1);
    };

    window.addEventListener("mousemove", handleMouseMove, { passive: true });
    document.addEventListener("mouseover", handleMouseOver, { passive: true });
    document.addEventListener("mouseout", handleMouseOut, { passive: true });

    return () => {
      window.removeEventListener("mousemove", handleMouseMove);
      document.removeEventListener("mouseover", handleMouseOver);
      document.removeEventListener("mouseout", handleMouseOut);
    };
  }, [cursorX, cursorY, scale]);

  return (
    <motion.div
      className="cursor-follower hidden md:block"
      style={{
        x,
        y,
        scale,
      }}
    />
  );
}

"use client";

import { useState, useRef, useCallback, useEffect } from "react";
import { motion, AnimatePresence } from "framer-motion";

interface FilterPanelProps {
  onFilterChange?: (filters: ActiveFilters) => void;
}

export interface ActiveFilters {
  genres: string[];
  mood: string | null;
  era: string | null;
  language: string | null;
  rating: string | null;
}

const GENRES = ["Action", "Drama", "Comedy", "Sci-Fi", "Horror", "Romance", "Thriller", "Animation"];
const MOODS = ["Mind-Bending", "Comfort", "Dark", "Uplifting", "Epic", "Romantic"];
const ERAS = ["Classic (pre-1980)", "80s & 90s", "2000s", "2010s", "Recent (2020+)"];
const LANGUAGES = ["English", "Korean", "Japanese", "French", "Spanish", "Hindi"];
const RATINGS = ["9+ Masterpiece", "8+ Excellent", "7+ Great", "Any"];

// All filter groups for keyboard navigation
const FILTER_GROUPS = [
  { key: "genres" as const, label: "Genre", items: GENRES, multi: true },
  { key: "mood" as const, label: "Mood", items: MOODS, multi: false },
  { key: "era" as const, label: "Era", items: ERAS, multi: false },
  { key: "language" as const, label: "Language", items: LANGUAGES, multi: false },
  { key: "rating" as const, label: "Rating", items: RATINGS, multi: false },
];

/*
  FilterPanel ΓÇö Glass UI with keyboard navigation
  ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
  - Glassmorphism backdrop (backdrop-filter: blur)
  - Animated open/close with spring easing
  - Keyboard nav: ArrowDown/ArrowUp between groups, ArrowLeft/ArrowRight between chips
  - Enter/Space to toggle chip, Escape to close panel
  - aria-expanded, role="listbox", role="option" for a11y
  - Active filter count badge
*/

export default function FilterPanel({ onFilterChange }: FilterPanelProps) {
  const [isOpen, setIsOpen] = useState(false);
  const panelRef = useRef<HTMLDivElement>(null);
  const triggerRef = useRef<HTMLButtonElement>(null);
  const [focusGroup, setFocusGroup] = useState(0);
  const [focusItem, setFocusItem] = useState(0);

  const [filters, setFilters] = useState<ActiveFilters>({
    genres: [],
    mood: null,
    era: null,
    language: null,
    rating: null,
  });

  // ΓöÇΓöÇ Toggle genre (multi-select) ΓöÇΓöÇ
  const toggleGenre = (genre: string) => {
    const newGenres = filters.genres.includes(genre)
      ? filters.genres.filter((g) => g !== genre)
      : [...filters.genres, genre];
    const newFilters = { ...filters, genres: newGenres };
    setFilters(newFilters);
    onFilterChange?.(newFilters);
  };

  // ΓöÇΓöÇ Set single-select filter ΓöÇΓöÇ
  const setFilter = (key: keyof ActiveFilters, value: string) => {
    const newFilters = {
      ...filters,
      [key]: filters[key] === value ? null : value,
    };
    setFilters(newFilters as ActiveFilters);
    onFilterChange?.(newFilters as ActiveFilters);
  };

  // ΓöÇΓöÇ Active filter count ΓöÇΓöÇ
  const activeCount =
    filters.genres.length +
    (filters.mood ? 1 : 0) +
    (filters.era ? 1 : 0) +
    (filters.language ? 1 : 0) +
    (filters.rating ? 1 : 0);

  // ΓöÇΓöÇ Close on outside click ΓöÇΓöÇ
  useEffect(() => {
    if (!isOpen) return;
    const handleClickOutside = (e: MouseEvent) => {
      if (
        panelRef.current &&
        !panelRef.current.contains(e.target as Node) &&
        triggerRef.current &&
        !triggerRef.current.contains(e.target as Node)
      ) {
        setIsOpen(false);
      }
    };
    document.addEventListener("mousedown", handleClickOutside);
    return () => document.removeEventListener("mousedown", handleClickOutside);
  }, [isOpen]);

  // ΓöÇΓöÇ Keyboard navigation ΓöÇΓöÇ
  const handleKeyDown = useCallback(
    (e: React.KeyboardEvent) => {
      if (!isOpen) return;

      const group = FILTER_GROUPS[focusGroup];

      switch (e.key) {
        case "Escape":
          setIsOpen(false);
          triggerRef.current?.focus();
          e.preventDefault();
          break;
        case "ArrowDown":
          setFocusGroup((g) => Math.min(g + 1, FILTER_GROUPS.length - 1));
          setFocusItem(0);
          e.preventDefault();
          break;
        case "ArrowUp":
          setFocusGroup((g) => Math.max(g - 1, 0));
          setFocusItem(0);
          e.preventDefault();
          break;
        case "ArrowRight":
          setFocusItem((i) => Math.min(i + 1, group.items.length - 1));
          e.preventDefault();
          break;
        case "ArrowLeft":
          setFocusItem((i) => Math.max(i - 1, 0));
          e.preventDefault();
          break;
        case "Enter":
        case " ":
          e.preventDefault();
          if (group.multi) {
            toggleGenre(group.items[focusItem]);
          } else {
            setFilter(group.key, group.items[focusItem]);
          }
          break;
      }
    },
    [isOpen, focusGroup, focusItem, filters]
  );

  // ΓöÇΓöÇ Check if a chip is active ΓöÇΓöÇ
  const isActive = (groupKey: string, item: string): boolean => {
    if (groupKey === "genres") return filters.genres.includes(item);
    return filters[groupKey as keyof ActiveFilters] === item;
  };

  return (
    <div className="relative z-30" onKeyDown={handleKeyDown}>
      {/* Toggle button */}
      <motion.button
        ref={triggerRef}
        onClick={() => setIsOpen(!isOpen)}
        whileTap={{ scale: 0.95 }}
        aria-expanded={isOpen}
        aria-haspopup="true"
        className="rounded-full px-5 py-2.5 flex items-center gap-2 cursor-pointer
          hover:shadow-lg transition-shadow duration-300"
        style={{
          background: "var(--glass-tint)",
          backdropFilter: "blur(20px)",
          WebkitBackdropFilter: "blur(20px)",
          border: "1px solid rgba(255, 255, 255, 0.4)",
          boxShadow: "var(--shadow-glass), inset 0 1px 0 rgba(255,255,255,0.5)",
        }}
        data-cursor-hover
      >
        <svg
          className="w-4 h-4 text-ink-soft"
          fill="none"
          viewBox="0 0 24 24"
          stroke="currentColor"
        >
          <path
            strokeLinecap="round"
            strokeLinejoin="round"
            strokeWidth={1.5}
            d="M10.5 6h9.75M10.5 6a1.5 1.5 0 11-3 0m3 0a1.5 1.5 0 10-3 0M3.75 6H7.5m3 12h9.75m-9.75 0a1.5 1.5 0 01-3 0m3 0a1.5 1.5 0 00-3 0m-3.75 0H7.5m9-6h3.75m-3.75 0a1.5 1.5 0 01-3 0m3 0a1.5 1.5 0 00-3 0m-9.75 0h9.75"
          />
        </svg>
        <span className="text-sm font-medium text-ink-light tracking-wide">
          Filters
        </span>
        {activeCount > 0 && (
          <motion.span
            initial={{ scale: 0 }}
            animate={{ scale: 1 }}
            transition={{ type: "spring", stiffness: 400, damping: 15 }}
            className="w-5 h-5 rounded-full bg-golden text-white text-xs flex items-center justify-center font-bold"
          >
            {activeCount}
          </motion.span>
        )}
      </motion.button>

      {/* Panel */}
      <AnimatePresence>
        {isOpen && (
          <motion.div
            ref={panelRef}
            initial={{ opacity: 0, y: 10, scale: 0.95 }}
            animate={{ opacity: 1, y: 0, scale: 1 }}
            exit={{ opacity: 0, y: 10, scale: 0.95 }}
            transition={{ duration: 0.4, ease: [0.19, 1, 0.22, 1] }}
            className="absolute top-14 right-0 w-[380px] max-h-[70vh] overflow-y-auto rounded-2xl p-6 shadow-xl"
            style={{
              background: "var(--glass-tint)",
              backdropFilter: "blur(24px)",
              WebkitBackdropFilter: "blur(24px)",
              border: "1px solid rgba(255, 255, 255, 0.35)",
              boxShadow:
                "0 25px 60px rgba(0,0,0,0.1), inset 0 1px 0 rgba(255,255,255,0.4)",
            }}
            role="dialog"
            aria-label="Filter options"
          >
            {FILTER_GROUPS.map((group, gi) => (
              <div key={group.key} className={gi < FILTER_GROUPS.length - 1 ? "mb-5" : ""}>
                <h4 className="font-display text-xs tracking-[0.2em] uppercase text-ink-muted mb-3">
                  {group.label}
                </h4>
                <div className="flex flex-wrap gap-2" role="listbox" aria-label={group.label}>
                  {group.items.map((item, ii) => {
                    const active = isActive(group.key, item);
                    const focused = gi === focusGroup && ii === focusItem;

                    return (
                      <button
                        key={item}
                        onClick={() =>
                          group.multi
                            ? toggleGenre(item)
                            : setFilter(group.key, item)
                        }
                        role="option"
                        aria-selected={active}
                        tabIndex={focused ? 0 : -1}
                        className={`filter-chip px-3 py-1.5 rounded-full text-xs font-medium border cursor-pointer
                          ${
                            active
                              ? "active"
                              : "bg-white/50 border-ink/10 text-ink-light hover:bg-white/80"
                          }
                          ${focused ? "ring-2 ring-golden/50 ring-offset-1" : ""}
                        `}
                      >
                        {item}
                      </button>
                    );
                  })}
                </div>
              </div>
            ))}
          </motion.div>
        )}
      </AnimatePresence>
    </div>
  );
}

